"use client";

import { useState } from "react";
import { useForm, FormProvider } from "react-hook-form";
import {
  Eye,
  EyeOff,
  Save,
  CheckCircle,
  AlertCircle,
  Loader,
} from "lucide-react";

import type { TourFormData } from "./constants/types";
import { defaultValues } from "./constants/types";
import { saveTourAction, updateTourAction } from "@/app/actions/toursAction";

import BasicInfoSection from "./sections/BasicInfoSection";
import MediaSection from "./sections/MediaSection";
import HighlightsSection from "./sections/HighlightsSection";
import LocationsSection from "./sections/LocationsSection";
import GuideSection from "./sections/GuideSection";
import PreviewPanel from "./sections/PreviewPanel";

type SaveState =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "success"; slug: string }
  | { status: "error"; message: string };

export default function TourForm({
  initialData,
  tourId,
}: {
  initialData?: any;
  tourId?: number;
}) {
  const [preview, setPreview] = useState(false);
  const [saveState, setSaveState] = useState<SaveState>({ status: "idle" });

  const methods = useForm<TourFormData>({
    defaultValues: initialData
      ? {
          slug: initialData.slug || "",
          title: initialData.title || "",
          description: initialData.description || "",
          fullDescription: initialData.fullDescription || "",
          image: initialData.image || "",
          video: initialData.video || "",
          highlights: (Math.random(), initialData.highlights || []).map(
            (h: string) => ({ id: Math.random().toString(), value: h })
          ),
          locations: (initialData.locations || []).map((l: any) => ({
            name: l.name || "",
            description: l.description || "",
            x: l.coordinates?.x || 50,
            y: l.coordinates?.y || 50,
          })),
          guideName: initialData.guide?.name || "",
          guideRole: initialData.guide?.role || "",
          guideTelegram: initialData.guide?.telegram || "",
        }
      : defaultValues,
    mode: "onChange",
  });

  const {
    watch,
    reset,
    formState: { isValid: rhfValid },
  } = methods;
  const values = watch();

  const canSave = !!(
    values.title?.trim() &&
    values.description?.trim() &&
    values.image?.trim()
  );

  const handleSave = async () => {
    if (!canSave) return;
    setSaveState({ status: "loading" });

    const inputData = {
      slug:
        values.slug ||
        values.title
          .toLowerCase()
          .replace(/\s+/g, "-")
          .replace(/[^a-z0-9-]/g, ""),
      title: values.title,
      description: values.description,
      fullDescription: values.fullDescription || undefined,
      image: values.image,
      video: values.video || undefined,
      highlights: values.highlights.map((h) => h.value).filter(Boolean),
      locations: values.locations
        .filter((l) => l.name.trim())
        .map((l) => ({
          name: l.name,
          description: l.description,
          coordinates: { x: l.x, y: l.y },
        })),
      guide: {
        name: values.guideName,
        role: values.guideRole,
        telegram: values.guideTelegram,
      },
    };

    let result;
    if (tourId) {
      result = await updateTourAction(tourId, inputData);
    } else {
      result = await saveTourAction(inputData);
    }

    if (result.success) {
      setSaveState({ status: "success", slug: result.slug! });
      if (!tourId) {
        reset(defaultValues); // clear form for next tour only if adding new
      }
    } else {
      setSaveState({ status: "error", message: result.error! });
    }
  };

  return (
    <FormProvider {...methods}>
      <form onSubmit={(e) => e.preventDefault()} noValidate className="pb-24">
        {/* Page header + action bar */}
        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-6 mb-10">
          <div>
            <p className="text-accent-cta text-xs font-black uppercase tracking-[0.4em] mb-2">
              Панель управления
            </p>
            <h1 className="text-4xl md:text-5xl font-black tracking-tighter text-light-surface">
              {tourId ? "Редактировать тур" : "Новый концепт"}
            </h1>
            <p className="text-light-surface/40 mt-2 text-sm">
              {tourId
                ? "Измените данные и сохраните, чтобы обновить концепт на сайте"
                : "Заполните форму и сохраните — концепт мгновенно появится на сайте"}
            </p>
          </div>

          <div className="flex items-center gap-3 shrink-0">
            {/* Preview toggle */}
            <button
              type="button"
              onClick={() => setPreview(!preview)}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl border text-sm font-semibold transition-all ${
                preview
                  ? "bg-light-surface/10 border-light-surface/20 text-light-surface"
                  : "border-light-surface/10 text-light-surface/50 hover:text-light-surface hover:border-light-surface/20"
              }`}
            >
              {preview ? <EyeOff size={15} /> : <Eye size={15} />}
              {preview ? "Скрыть" : "Превью"}
            </button>

            {/* Save button */}
            <button
              type="button"
              onClick={handleSave}
              disabled={!canSave || saveState.status === "loading"}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all duration-300 ${
                !canSave || saveState.status === "loading"
                  ? "bg-light-surface/5 border border-light-surface/5 text-light-surface/20 cursor-not-allowed"
                  : saveState.status === "success"
                  ? "bg-green-500/20 border border-green-500/40 text-green-400"
                  : saveState.status === "error"
                  ? "bg-red-500/20 border border-red-500/40 text-red-400"
                  : "bg-accent-cta hover:bg-accent-cta/80 text-light-surface shadow-[0_0_20px_rgba(194,56,28,0.35)]"
              }`}
            >
              {saveState.status === "loading" ? (
                <Loader size={15} className="animate-spin" />
              ) : saveState.status === "success" ? (
                <CheckCircle size={15} />
              ) : saveState.status === "error" ? (
                <AlertCircle size={15} />
              ) : (
                <Save size={15} />
              )}
              {saveState.status === "loading"
                ? "Сохранение..."
                : saveState.status === "success"
                ? "Сохранено!"
                : saveState.status === "error"
                ? "Ошибка"
                : tourId
                ? "Сохранить изменения"
                : "Сохранить в БД"}
            </button>
          </div>
        </div>

        {/* Status banner */}
        {saveState.status === "success" && (
          <div className="mb-8 p-4 rounded-2xl bg-green-500/10 border border-green-500/30 flex items-start gap-3">
            <CheckCircle size={18} className="text-green-400 mt-0.5 shrink-0" />
            <div>
              <p className="text-green-400 font-semibold text-sm">
                Концепт успешно {tourId ? "обновлен" : "добавлен"}!
              </p>
              <p className="text-green-400/60 text-xs mt-1">
                Доступен по адресу{" "}
                <a
                  href={`/tours/${saveState.slug}`}
                  className="underline hover:text-green-300"
                  target="_blank"
                >
                  /tours/{saveState.slug}
                </a>{" "}
                {tourId
                  ? "· Данные успешно обновлены"
                  : "· Форма очищена для нового концепта"}
              </p>
            </div>
          </div>
        )}

        {saveState.status === "error" && (
          <div className="mb-8 p-4 rounded-2xl bg-red-500/10 border border-red-500/30 flex items-start gap-3">
            <AlertCircle size={18} className="text-red-400 mt-0.5 shrink-0" />
            <div>
              <p className="text-red-400 font-semibold text-sm">
                Не удалось сохранить
              </p>
              <p className="text-red-400/60 text-xs mt-1">
                {saveState.message}
              </p>
            </div>
          </div>
        )}

        {/* Main layout */}
        <div
          className={`grid gap-10 ${
            preview
              ? "grid-cols-1 lg:grid-cols-12"
              : "grid-cols-1 max-w-3xl mx-auto"
          }`}
        >
          {/* Sections column */}
          <div className={`space-y-6 ${preview ? "lg:col-span-7" : ""}`}>
            <BasicInfoSection />
            <MediaSection />
            <HighlightsSection />
            <LocationsSection />
            <GuideSection />
          </div>

          {/* Preview column */}
          {preview && <PreviewPanel />}
        </div>
      </form>
    </FormProvider>
  );
}

"use client";

import { useFormContext } from "react-hook-form";
import {
  Image as ImageIcon,
  Film,
  Check,
  Link as LinkIcon,
  FolderOpen,
} from "lucide-react";
import { useState } from "react";
import type { TourFormData } from "../constants/types";
import { inputClass } from "../constants/constants";
import SectionCard from "@/app/shared/ui/SectionCard";
import FormField from "@/app/shared/ui/FormField";

/** Converts any YouTube URL variant to an embed URL.
 *  Handles: watch?v=, youtu.be/, shorts/, and already-embed URLs. */
function toYoutubeEmbed(raw: string): string {
  if (!raw) return raw;

  // Already an embed link — return as is
  if (raw.includes("youtube.com/embed/")) return raw;

  // Regex to extract video ID from all known YouTube URL patterns
  const match = raw.match(
    /(?:youtube\.com\/(?:watch\?(?:.*&)?v=|shorts\/)|youtu\.be\/)([a-zA-Z0-9_-]{11})/
  );

  if (match) {
    // Preserve si= parameter if present
    const siMatch = raw.match(/[?&]si=([^&]+)/);
    const si = siMatch ? `?si=${siMatch[1]}` : "";
    return `https://www.youtube.com/embed/${match[1]}${si}`;
  }

  return raw;
}

function isExternalUrl(val: string) {
  return val.startsWith("http://") || val.startsWith("https://");
}

export default function MediaSection() {
  const {
    register,
    watch,
    setValue,
    formState: { errors },
  } = useFormContext<TourFormData>();

  const imageSrc = watch("image");
  const videoSrc = watch("video");

  // When user leaves the video field — auto-convert to embed URL
  const handleVideoBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    const converted = toYoutubeEmbed(e.target.value.trim());
    if (converted !== e.target.value) {
      setValue("video", converted);
    }
  };

  const imageIsExternal = isExternalUrl(imageSrc ?? "");

  return (
    <SectionCard title="Медиа" icon={<ImageIcon size={18} />}>
      {/* Image */}
      <FormField
        label="Изображение"
        hint="локальный путь или внешняя ссылка"
        error={errors.image?.message}
      >
        <div className="flex gap-3 items-start">
          <div className="flex-1 space-y-2">
            <div className="relative">
              {/* Icon: link or folder depending on content */}
              <div className="absolute left-4 top-1/2 -translate-y-1/2 text-light-surface/25 pointer-events-none">
                {imageIsExternal ? (
                  <LinkIcon size={15} />
                ) : (
                  <FolderOpen size={15} />
                )}
              </div>
              <input
                className={inputClass + " pl-10"}
                placeholder="/beijing.png  или  https://..."
                {...register("image", {
                  required: "Укажите путь или ссылку на изображение",
                })}
              />
            </div>

            {/* Hint chips */}
            <div className="flex gap-2 flex-wrap">
              <span className="text-[10px] px-2 py-1 rounded-full bg-light-surface/5 border border-light-surface/10 text-light-surface/30">
                /public/beijing.png
              </span>
              <span className="text-[10px] px-2 py-1 rounded-full bg-light-surface/5 border border-light-surface/10 text-light-surface/30">
                https://images.example.com/photo.jpg
              </span>
            </div>
          </div>

          {/* Live thumbnail */}
          {imageSrc && (
            <div className="w-16 h-16 shrink-0 rounded-xl overflow-hidden border border-light-surface/10 bg-light-surface/5">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={imageSrc}
                alt=""
                className="w-full h-full object-cover"
                onError={(e) => {
                  e.currentTarget.style.opacity = "0.2";
                  e.currentTarget.style.filter = "grayscale(1)";
                }}
                onLoad={(e) => {
                  e.currentTarget.style.opacity = "1";
                  e.currentTarget.style.filter = "none";
                }}
              />
            </div>
          )}
        </div>
      </FormField>

      {/* Video */}
      <FormField
        label="Видео"
        hint="YouTube ссылка любого формата (необязательно)"
        error={errors.video?.message}
      >
        <div className="relative">
          <Film
            size={15}
            className="absolute left-4 top-1/2 -translate-y-1/2 text-light-surface/25 pointer-events-none"
          />
          <input
            className={inputClass + " pl-10"}
            placeholder="https://youtu.be/...  или  youtube.com/watch?v=..."
            {...register("video")}
            onBlur={handleVideoBlur}
          />
        </div>

        {videoSrc && (
          <>
            <p className="text-xs text-green-400/70 flex items-center gap-1.5 pt-1">
              <Check size={12} />
              {videoSrc.includes("youtube.com/embed/")
                ? "Embed-ссылка готова"
                : "Видео добавлено"}
            </p>
            {/* Mini embed preview */}
            {videoSrc.includes("youtube.com/embed/") && (
              <div className="mt-3 rounded-xl overflow-hidden border border-light-surface/10 aspect-video">
                <iframe
                  src={videoSrc}
                  className="w-full h-full"
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                  allowFullScreen
                />
              </div>
            )}
          </>
        )}
      </FormField>
    </SectionCard>
  );
}

"use client";

import Link from "next/link";
import { Plus, Edit2, Trash2, MapPin } from "lucide-react";
import { useState } from "react";
import { deleteTourAction } from "@/app/actions/toursAction";

export default function AdminToursList({ tours }: { tours: any[] }) {
  const [isDeleting, setIsDeleting] = useState<number | null>(null);

  const handleDelete = async (id: number) => {
    if (
      !confirm(
        "Вы уверены, что хотите удалить этот тур? Это действие нельзя отменить."
      )
    )
      return;
    setIsDeleting(id);
    const res = await deleteTourAction(id);
    if (!res.success) {
      alert(res.error || "Ошибка удаления");
    }
    setIsDeleting(null);
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl md:text-5xl font-black tracking-tighter text-light-surface uppercase">
            Туры
          </h1>
          <p className="text-light-surface/40 mt-2 text-sm">
            Управление маршрутами и экскурсиями
          </p>
        </div>

        <Link
          href="/admin/tours/create"
          className="flex items-center gap-2 px-6 py-3 rounded-full bg-accent-cta hover:bg-accent-cta/90 text-light-surface font-black uppercase tracking-widest text-sm transition-all shadow-[0_0_20px_rgba(194,56,28,0.35)] shrink-0"
        >
          <Plus size={16} />
          Создать новый
        </Link>
      </div>

      {tours.length === 0 ? (
        <div className="h-64 flex flex-col items-center justify-center border border-dashed border-light-surface/10 rounded-4xl bg-light-surface/5">
          <MapPin className="text-light-surface/20 w-12 h-12 mb-4" />
          <p className="text-light-surface/40 font-semibold">
            У вас пока нет добавленных туров
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {tours.map((tour) => (
            <div
              key={tour.id}
              className="bg-light-surface/5 border border-light-surface/10 rounded-3xl overflow-hidden group hover:border-light-surface/20 transition-all flex flex-col"
            >
              <div className="h-48 overflow-hidden relative">
                <img
                  src={tour.image}
                  alt={tour.title}
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
                />
                <div className="absolute inset-0 bg-linear-to-t from-black/80 to-transparent" />
                <div className="absolute bottom-4 left-4 right-4">
                  <h3 className="text-2xl font-black text-white">
                    {tour.title}
                  </h3>
                </div>
              </div>

              <div className="p-6 flex-1 flex flex-col">
                <p className="text-light-surface/60 text-sm line-clamp-3 mb-6 flex-1">
                  {tour.description}
                </p>

                <div className="flex items-center gap-3 pt-6 border-t border-light-surface/10">
                  <Link
                    href={`/admin/tours/edit/${tour.id}`}
                    className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl bg-light-surface/10 hover:bg-light-surface/20 text-light-surface font-semibold text-sm transition-colors"
                  >
                    <Edit2 size={16} /> Редактировать
                  </Link>
                  <button
                    onClick={() => handleDelete(tour.id)}
                    disabled={isDeleting === tour.id}
                    className="w-12 h-12 flex items-center justify-center rounded-xl bg-red-500/10 hover:bg-red-500/20 text-red-400 transition-colors shrink-0 disabled:opacity-50"
                    title="Удалить тур"
                  >
                    {isDeleting === tour.id ? (
                      <div className="w-4 h-4 border-2 border-red-400 border-t-transparent rounded-full animate-spin" />
                    ) : (
                      <Trash2 size={18} />
                    )}
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

