"use client";

import {
  Calendar,
  Users,
  MessageSquare,
  Send,
  Mail,
  Sparkles,
  MapPin,
} from "lucide-react";
import { useState, useEffect } from "react";
import { useEmailStore } from "@/app/actions/store/email";
import { sendBookingToTelegram } from "@/app/actions/bookingAction";
import type { Tour } from "@/app/data/tours";

export default function BookingForm({ tours }: { tours: Tour[] }) {
  const { email } = useEmailStore();
  const [formData, setFormData] = useState({
    tour: "",
    date: "",
    people: "1",
    email: email,
    telegram: "",
    message: "",
  });

  useEffect(() => {
    if (email) {
      setFormData((prev) => ({ ...prev, email }));
    }
  }, [email]);

  const [status, setStatus] = useState<
    "idle" | "loading" | "success" | "error"
  >("idle");
  const [errorMessage, setErrorMessage] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus("loading");
    setErrorMessage("");

    try {
      const result = await sendBookingToTelegram(formData);
      if (result.success) {
        setStatus("success");
      } else {
        setStatus("error");
        setErrorMessage(result.error || "Произошла ошибка при отправке");
      }
    } catch (err) {
      setStatus("error");
      setErrorMessage("Сетевая ошибка");
    }
  };

  if (status === "success") {
    return (
      <section className="py-24 relative overflow-hidden">
        <div className="container mx-auto px-6 text-center">
          <div className="max-w-2xl mx-auto p-12 rounded-[3.5rem] bg-white/5 border border-accent-cta/30 backdrop-blur-xl space-y-8 animate-in zoom-in duration-500">
            <div className="w-24 h-24 bg-accent-cta rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-accent-cta/50">
              <Sparkles className="text-white" size={48} />
            </div>
            <h2 className="text-4xl md:text-5xl font-black text-white uppercase tracking-tighter">
              Заявка принята!
            </h2>
            <p className="text-xl text-white/50 font-light leading-relaxed">
              Спасибо за ваш интерес! Лев или наш менеджер свяжется с вами в
              Telegram или по Email в течение ближайшего времени.
            </p>
            <div className="pt-6">
              <button
                onClick={() => setStatus("idle")}
                className="text-accent-cta font-bold uppercase tracking-widest text-xs hover:underline"
              >
                Отправить еще одну заявку
              </button>
            </div>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section id="form" className="py-24 relative overflow-hidden">
      <div className="container mx-auto px-6">
        <div className="flex flex-col lg:flex-row gap-20 items-stretch">
          {/* Form Side */}
          <div className="w-full lg:w-2/3">
            <form onSubmit={handleSubmit} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                {/* Tour Selection */}
                <div className="space-y-4 md:col-span-2">
                  <label className="flex items-center gap-2 text-xs font-black uppercase tracking-widest text-accent-cta">
                    <MapPin size={14} /> Какой тур или экскурсия вас интересует?
                  </label>
                  <select
                    className="w-full bg-white/5 border-b border-white/10 py-4 px-2 text-xl focus:border-accent-cta outline-none transition-all text-white appearance-none cursor-pointer"
                    onChange={(e) =>
                      setFormData({ ...formData, tour: e.target.value })
                    }
                    value={formData.tour}
                  >
                    <option value="" disabled className="bg-dark-section">
                      Выберите маршрут или экскурсию...
                    </option>
                    <option
                      value="Индивидуальный маршрут"
                      className="bg-dark-section font-bold text-accent-cta"
                    >
                      ✨ Индивидуальный маршрут (составим под вас)
                    </option>
                    <option
                      value="Большой тур"
                      className="bg-dark-section font-bold text-accent-cta"
                    >
                      Большой тур (Шанхай, Горы Аватара, Восточная Венеция)
                    </option>
                    {tours.map((tour) => (
                      <option
                        key={tour.id}
                        value={tour.title}
                        className="bg-dark-section"
                      >
                        {tour.title}
                      </option>
                    ))}
                  </select>
                </div>

                {/* Date Selection */}
                <div className="space-y-4">
                  <label className="flex items-center gap-2 text-xs font-black uppercase tracking-widest text-accent-cta">
                    <Calendar size={14} /> Желаемая дата начала
                  </label>
                  <input
                    type="date"
                    required
                    className="w-full bg-white/5 border-b border-white/10 py-4 px-2 text-xl focus:border-accent-cta outline-none transition-all text-white appearance-none"
                    onChange={(e) =>
                      setFormData({ ...formData, date: e.target.value })
                    }
                  />
                </div>

                {/* People Count */}
